module freq_divbyfrac #(
    parameter MUL2_DIV_CLK = 7
) (
    input               rst_n,
    input               clk,
    output              clk_div
);

reg [3:0] cnt;
reg clk_ave_r, clk_adjust_r;
always@(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		cnt <= 4'd0;
	end
	else begin
		if(cnt >= MUL2_DIV_CLK - 1) cnt <= 4'd0;
		else cnt <= cnt + 1;
	end
end
always@(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		clk_ave_r <= 1'b0;
	end
	else begin
		case(cnt)
			4'd0, 4'd4: clk_ave_r <= 1'b1;
			default: clk_ave_r <= 1'b0;
		endcase
	end
end
always@(negedge clk or negedge rst_n) begin
	if(!rst_n) begin
		clk_adjust_r <= 1'b0;
	end
	else begin
		case(cnt)
			4'd1, 4'd4: clk_adjust_r <= 1'b1;
			default: clk_adjust_r <= 1'b0;
		endcase
	end
end
assign clk_div = clk_adjust_r | clk_ave_r;
endmodule
